use std::collections::BTreeSet;

struct ProductCode {
    id: String,
}

impl PartialEq for ProductCode {
    fn eq(&self, other: &Self) -> bool {
        self.id == other.id
    }
}

impl Eq for ProductCode {}

impl PartialOrd for ProductCode {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for ProductCode {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.id.cmp(&other.id)
    }
}

fn main() {
    let code1 = ProductCode { id: "XYZ-900".to_string() };
    let code2 = ProductCode { id: "ABC-100".to_string() };
    let code3 = ProductCode { id: "XYZ-900".to_string() };

    let mut unique_codes: BTreeSet<ProductCode> = BTreeSet::new();
    unique_codes.insert(code1);
    unique_codes.insert(code2);
    unique_codes.insert(code3);

    println!("Number of unique codes found: {}", unique_codes.len());
}

