use std::collections::BTreeSet;

#[derive(Debug)]
struct Product {
    id: u32,
    name: String,
    price: f64,
}

impl PartialEq for Product {
    fn eq(&self, other: &Self) -> bool {
        self.id == other.id && self.name == other.name
    }
}

impl Eq for Product {}

impl PartialOrd for Product {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Product {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.id.cmp(&other.id)
            .then_with(|| self.name.cmp(&other.name))
            .then_with(|| self.price.total_cmp(&other.price))
    }
}

fn main() {
    let product1 = Product { id: 10, name: "Widget".to_string(), price: 5.99 };
    let product2 = Product { id: 20, name: "Gadget".to_string(), price: 12.00 };
    let product3 = Product { id: 10, name: "Widget".to_string(), price: 5.99 };

    let mut set: BTreeSet<Product> = std::collections::BTreeSet::new();
    set.insert(product1);
    set.insert(product2);
    set.insert(product3);

    println!("Items in the sorted collection:");
    for item in set {
        println!("{:?}", item);
    }
}

