use std::collections::BTreeSet;

#[derive(Debug)]
struct ProductKey {
    sku: u32,
    name: String,
}

impl PartialEq for ProductKey {
    fn eq(&self, other: &Self) -> bool {
        self.sku == other.sku && self.name == other.name
    }
}

impl Eq for ProductKey {}

impl PartialOrd for ProductKey {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for ProductKey {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        match self.sku.cmp(&other.sku) {
            std::cmp::Ordering::Equal => self.name.cmp(&other.name),
            other => other
        }
    }
}

fn main() {
    let mut unique_products: BTreeSet<ProductKey> = BTreeSet::new();
    unique_products.insert(ProductKey { sku: 101, name: "Monitor".to_string() });
    unique_products.insert(ProductKey { sku: 205, name: "Keyboard".to_string() });
    unique_products.insert(ProductKey { sku: 101, name: "Monitor".to_string() });

    println!("Unique keys sorted and stored: {:#?}", unique_products);
}
